// Let's format the result into an easy understandable / edge-like form
| fields within_same_namespace = references[belongs_to.k8s_namespace] == dt.traverse.history[0][belongs_to.k8s_namespace], source_id = dt.traverse.history[0][id], source_type = dt.traverse.history[0][type], source_name = dt.traverse.history[0][name], type="calls", target_id = id, target_name = name, target_type = type

